BoundedContext BlogContext {
    Aggregate BlogPost {
        @identity postId: UUID
        title: String @required @maxLength(200)
        content: String
        status: String

        operations {
            when publishing {
                require that title is not empty
                require that content is not empty
                then set status to "PUBLISHED"
                emit event PostPublished
            }
        }
    }

    DomainEvent PostPublished {
        postId: UUID
    }
}

BoundedContext OrderContext {
    Aggregate Order {
        @identity orderId: UUID
        customerId: UUID @required
        totalAmount: Decimal @min(0)
        orderDate: DateTime

        Entity OrderItem {
            @identity itemId: UUID
            productName: String @required
            quantity: Int @min(1)
            unitPrice: Decimal
        }

        operations {
            when adding item {
                require that quantity is greater than 0
                then add to items
            }
        }
    }
}

BoundedContext ECommerceContext {
    Aggregate Order {
        @identity orderId: UUID
        customerId: UUID
        items: List<OrderItem>
        totalAmount: Decimal
        status: String

        Entity OrderItem {
            productId: UUID
            productName: String
            quantity: Int
            unitPrice: Decimal
        }

        operations {
            when placing order {
                require that items is not empty
                then calculate total from sum of item prices
                then set status to "PENDING"
                emit event OrderPlaced
            }
        }
    }

    Repository OrderRepository for Order {
        findByCustomerId(customerId: UUID): List<Order>
        findByStatus(status: String): List<Order>
    }
}

BoundedContext BankingContext {
    Aggregate Account {
        @identity accountId: UUID
        customerId: UUID
        accountNumber: String
        balance: Decimal @min(0)

        operations {
            when opening {
                require that balance is greater than minimum deposit
                then set status to "ACTIVE"
                emit event AccountOpened
            }

            when withdrawing with amount {
                require that balance is greater than amount
                then decrease balance by amount
                emit event WithdrawalMade
            }
        }
    }
}
